import{_ as t,o as p,c as l,ag as e}from"./chunks/framework.DXGyWiRo.js";const i="/media/202508/2025-08-14_142018_6626390.19383209440389215.png",r="/media/202508/2025-08-14_143002_6011740.3638648107769974.png",n="/media/202508/2025-08-14_143204_5861110.8506114938355781.png",o="/media/202508/2025-08-14_143224_7044970.8223657835727379.png",s="/media/202508/2025-08-14_143528_8834420.6333885998346772.png",_="/media/202508/2025-08-14_143546_6315190.6171034000733273.png",c="/media/202508/2025-08-14_143648_4059940.419974136812609.png",m="/media/202508/2025-08-14_143703_8019310.3388137217897015.png",d="/media/202508/2025-08-14_144217_6728960.6431335842061348.png",h="/media/202508/2025-08-14_144243_0061710.9009890673635944.png",x=JSON.parse('{"title":"星火大模型配置","description":"","frontmatter":{"title":"星火大模型配置"},"headers":[],"relativePath":"app-config/spark-llm.md","filePath":"app-config/spark-llm.md","lastUpdated":null}'),g={name:"app-config/spark-llm.md"};function u(f,a,b,k,q,I){return p(),l("div",null,[...a[0]||(a[0]=[e('<p>星火大模型配置概述</p><p>该配置项是传统应用开启大模型能力的开关，配置项的处理关系到两个服务链路的切换：</p><p><strong>- 开启星火大模型配置</strong></p><p>此时AIUI应用服务切换到通用大模型交互链路，支持文档问答、旧版智能体、联网搜索、知识溯源配置。</p><p><strong>- 关闭星火大模型配置</strong></p><p>此时AIUI应用服务切换到传统语义链路，不支持大模型服务请求。</p><p>相关配置项：</p><h2 id="配置说明" tabindex="-1">配置说明 <a class="header-anchor" href="#配置说明" aria-label="Permalink to &quot;配置说明&quot;">​</a></h2><p>开关大模型配置时，平台将进行弹窗提示，告知当前操作对应的AIUI服务链路将进行变更，开发者做AIUI集成开发时，需要重点关注端侧协议的切换和结果解析。</p><p>温馨提示</p><p>星火大模型配置关闭后，下方的配置项就算有配置开启，能力也将不再生效。因为此时AIUI服务切换到传统语义链路，不再支持大模型相关能力。</p><p><img src="'+i+'" alt="" title="null"><img src="'+r+'" alt="" title="null"></p><h2 id="问答" tabindex="-1">问答 <a class="header-anchor" href="#问答" aria-label="Permalink to &quot;问答&quot;">​</a></h2><p>该配置项是给通用大模型服务链路配置自定义大模型链路的<strong>文档问答</strong>。</p><h4 id="_2-1-文档问答配置" tabindex="-1">2.1. 文档问答配置 <a class="header-anchor" href="#_2-1-文档问答配置" aria-label="Permalink to &quot;2.1. 文档问答配置&quot;">​</a></h4><p>点击“添加”，可以配置当前账号下创建并发布好的文档问答</p><p><img src="'+n+'" alt="" title="null"></p><p><img src="'+o+'" alt="" title="null"></p><h4 id="_2-2-文档问答设置" tabindex="-1">2.2. 文档问答设置 <a class="header-anchor" href="#_2-2-文档问答设置" aria-label="Permalink to &quot;2.2. 文档问答设置&quot;">​</a></h4><p>点击“设置”，可以对文档问答生效策略进行配置【针对所有文档问答生效】，包括：</p><ul><li>检索方法 <ul><li>单向量召回</li><li>多路召回</li></ul></li><li>相关性阈值</li></ul><p>知识说明</p><p>1、相关性就是知识片段和用户问题的匹配程度，数值在 0 到 1 之间。这个值越高，说明这个知识片段越有可能帮你答好问题。</p><p>2、检索方法就是计算相关性的方法。单向量召回是靠算语义向量的相似度来得出结果；多路召回则是把语义向量、关键词等多种方式的相似度合起来计算。</p><p>为了筛选出足够匹配的知识片段，会设定一个 “相关性阈值”—— 比如阈值设为 0.6，就意味着只保留相关性数值≥0.6 的知识片段，低于这个值的会被排除，避免不相关的知识干扰回答。</p><p><img src="'+s+'" alt="" title="null"></p><p><img src="'+_+'" alt="" title="null"></p><h2 id="智能体" tabindex="-1">智能体 <a class="header-anchor" href="#智能体" aria-label="Permalink to &quot;智能体&quot;">​</a></h2><p>该配置项是给通用大模型服务链路配置自定义大模型链路的<strong>旧版智能体</strong>。 点击“添加”，可以配置当前账号下创建并发布好的新版智能体，点击“创建智能体”也可以跳转到智能体开发界面进行自定义智能体开发。</p><p>知识说明</p><p>1、旧版智能体：仅提供意图匹配能力，开发者编辑时仅提供语料设置</p><p>2、新版智能体：除提供意图匹配能力，开发者可以按照业务需要进行节点能力模块自定义编辑。与目前主流智能体开发方式基本保持一致</p><p><img src="'+c+'" alt="" title="null"></p><p><img src="'+m+'" alt="" title="null"></p><h2 id="搜索引擎" tabindex="-1">搜索引擎 <a class="header-anchor" href="#搜索引擎" aria-label="Permalink to &quot;搜索引擎&quot;">​</a></h2><p>该项提供大模型联网搜索能力项，默认是关闭的，开发者可以自行进行开启。 当开启后用户进行语音交互时，当服务判断需要进行搜索时，会调用联网服务进行信息搜索，然后大模型对搜索的信息进行总结答复。</p><p><img src="'+d+'" alt="" title="null"></p><h2 id="知识溯源" tabindex="-1">知识溯源 <a class="header-anchor" href="#知识溯源" aria-label="Permalink to &quot;知识溯源&quot;">​</a></h2><p>该能力项主要是控制大模型服务结果下发的，通常作为服务链路中加载文档问答或联网搜索获取的知识点，内容比较多，默认是不下发的。当开发者需要了解大模型回复的内容从哪里获取的时候，可以开启该能力项，开启后AIUI服务在交互时，会新增下发 cbm_knowledge 结果。</p><p><img src="'+h+'" alt="" title="null"></p>',40)])])}const A=t(g,[["render",u]]);export{x as __pageData,A as default};
